
'use server';

/**
 * @fileOverview An AI flow that transforms two uploaded images into a short video of the people kissing realistically.
 *
 * - generateKissVideo - A function that handles the video generation process.
 * - GenerateKissVideoInput - The input type for the generateKissVideo function.
 * - GenerateKissVideoOutput - The return type for the generateKissVideo function.
 */

import {ai} from '@/ai/genkit';
import {z} from 'genkit';
import type {Part} from 'genkit';

const GenerateKissVideoInputSchema = z.object({
  image1DataUri: z
    .string()
    .describe(
      "The first image as a data URI that must include a MIME type and use Base64 encoding. Expected format: 'data:<mimetype>;base64,<encoded_data>'"
    ),
  image2DataUri: z
    .string()
    .describe(
      "The second image as a data URI that must include a MIME type and use Base64 encoding. Expected format: 'data:<mimetype>;base64,<encoded_data>'."
    ),
});

export type GenerateKissVideoInput = z.infer<typeof GenerateKissVideoInputSchema>;

const GenerateKissVideoOutputSchema = z.object({
  videoDataUri: z.string().optional().describe('The generated video as a data URI.'),
  sourceImageDataUri: z.string().optional().describe('The source image used for the video generation as a data URI.'),
  error: z.string().optional().describe('An error message if the generation failed.'),
});

export type GenerateKissVideoOutput = z.infer<typeof GenerateKissVideoOutputSchema>;

export async function generateKissVideo(input: GenerateKissVideoInput): Promise<GenerateKissVideoOutput> {
  try {
    const result = await generateKissVideoFlow(input);
    return result;
  } catch (e) {
    const message = e instanceof Error ? e.message : 'Unknown flow error';
    return { error: `Flow failed catastrophically: ${message}` };
  }
}

// Helper function to convert data URI to MediaPart
const toMediaPart = (dataUri: string): Part => {
  const match = dataUri.match(/^data:(image\/\w+);base64,(.*)$/);
  if (!match) {
    throw new Error('Invalid data URI format');
  }
  return {
    media: {
      contentType: match[1],
      url: dataUri,
    },
  };
};

// Fuses two images into one using an image generation model.
async function fuseImages(image1DataUri: string, image2DataUri: string): Promise<string> {
    const prompt: Part[] = [
      toMediaPart(image1DataUri),
      toMediaPart(image2DataUri),
      { text: `Fuse these two images of people into a single, realistic, horizontal, romantic image where they are positioned close to each other, ready to kiss.` },
    ];

    try {
        const { media } = await ai.generate({
          model: 'googleai/gemini-2.0-flash-preview-image-generation',
          prompt,
          config: { responseModalities: ['IMAGE', 'TEXT'] },
        });

        if (!media || !media.url) {
          throw new Error('Image fusion model did not return an image. Please try with clearer photos.');
        }
        return media.url;
    } catch(e) {
        const message = e instanceof Error ? e.message : 'Unknown error';
        throw new Error(`Failed to fuse images: ${message}`);
    }
}


const generateKissVideoFlow = ai.defineFlow(
  {
    name: 'generateKissVideoFlow',
    inputSchema: GenerateKissVideoInputSchema,
    outputSchema: GenerateKissVideoOutputSchema,
  },
  async input => {
    let sourceImageDataUri: string;
    let videoPromptText: string;

    try {
      sourceImageDataUri = await fuseImages(input.image1DataUri, input.image2DataUri);
    } catch(e) {
      const message = e instanceof Error ? e.message : 'Unknown error';
      // Return a structured error that can be displayed to the user.
      return { error: `Image fusion failed: ${message}. Please try using different, clearer photos.` };
    }

    videoPromptText = `Create a video based on the provided image, which contains two people. Scene: A single, static, wide shot. Do not use any camera movement or zooming. The video must be a single continuous shot with no cuts. Animation: 1. Animate the two people within the image. 2. They should turn to face each other and move together naturally. 3. They share a fluid, realistic, and tender kiss. The animation must be smooth and immediate as they come together. The animation must retain their likenesses and proportions from the original image and include natural body and arm movements for added realism.`;
    
    const videoPromptContent: Part[] = [
        { text: videoPromptText },
        toMediaPart(sourceImageDataUri),
    ];

    let {operation} = await ai.generate({
      model: 'googleai/veo-2.0-generate-001',
      prompt: videoPromptContent,
      config: {
        durationSeconds: 8,
        aspectRatio: '16:9',
        personGeneration: 'allow_adult',
      },
    });

    if (!operation) {
      throw new Error('Expected the video generation model to return an operation');
    }

    let pollCount = 0;
    while (!operation.done) {
      pollCount++;
      // Wait 5 seconds before checking again.
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await ai.checkOperation(operation);
      if (pollCount > 24) { // 2-minute timeout
        throw new Error('Video generation timed out.');
      }
    }


    if (operation.error) {
      throw new Error(`Video generation failed: ${operation.error.message || 'Unknown error'}`);
    }

    const videoPart = operation.output?.message?.content.find(p => !!p.media);
    if (!videoPart || !videoPart.media || !videoPart.media.url) {
      throw new Error('Could not find the generated video in the model response.');
    }
    
    const videoUrl = videoPart.media.url;
    const apiKey = process.env.GEMINI_API_KEY;
    
    if (!apiKey) {
      throw new Error("GEMINI_API_KEY is not set. Cannot download video.");
    }

    const fetch = (await import('node-fetch')).default;
    const videoDownloadResponse = await fetch(`${videoUrl}&key=${apiKey}`);
    
    if (!videoDownloadResponse.ok || !videoDownloadResponse.body) {
        throw new Error(`Failed to download the generated video. Status: ${videoDownloadResponse.status}`);
    }

    const videoBuffer = await videoDownloadResponse.arrayBuffer();
    const videoDataUri = `data:video/mp4;base64,${Buffer.from(videoBuffer).toString('base64')}`;
    
    return {videoDataUri, sourceImageDataUri};
  }
);
